import { useEffect, useState } from "react";
import PageHeader from "../components/PageHeader";
import { getAdminAppointments, updateAdminAppointment } from "../services/api";

export default function AdminAppointmentsPage() {
  const [items, setItems] = useState([]);

  const load = async () => setItems(await getAdminAppointments());
  useEffect(() => { load(); }, []);

  const updateStatus = async (appointmentId, status) => {
    await updateAdminAppointment(appointmentId, status);
    load();
  };

  return (
    <>
      <PageHeader title="Appointment Management" description="Approve and cancel requests from a page focused entirely on scheduling workflows." />
      <div className="panel">
        <div className="table-wrap">
          <table>
            <thead>
              <tr><th>Patient</th><th>Hospital</th><th>Date & Time</th><th>Status</th><th>Action</th></tr>
            </thead>
            <tbody>
              {items.map((item) => (
                <tr key={item.id}>
                  <td>{item.user.name}</td>
                  <td>{item.hospital_name}</td>
                  <td>{item.appointment_date} {item.appointment_time}</td>
                  <td><span className="pill">{item.status}</span></td>
                  <td>
                    <div className="button-row">
                      <button className="btn btn-primary" onClick={() => updateStatus(item.id, "approved")}>Approve</button>
                      <button className="btn btn-danger" onClick={() => updateStatus(item.id, "cancelled")}>Cancel</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </>
  );
}
